import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Toaster } from 'react-hot-toast';
import { AuthProvider } from './context/AuthContext';
import Navbar from './components/common/Navbar';
import PrivateRoute from './components/common/PrivateRoute';

import LoginPage        from './pages/LoginPage';
import CreateOrderPage  from './pages/CreateOrderPage';
import MyOrdersPage     from './pages/MyOrdersPage';
import TrackingPage     from './pages/TrackingPage';
import CourierDashboard from './pages/CourierDashboard';
import AdminDashboard   from './pages/AdminDashboard';

function HomePage() {
  return (
    <div style={{ maxWidth:680, margin:'40px auto', padding:16, textAlign:'center' }}>
      <h1 style={{ fontFamily:'Syne,sans-serif', fontWeight:800, fontSize:32, color:'#0D7A6A' }}>
        Xorazm<span style={{ color:'#EF9F27' }}>Delivery</span>
      </h1>
      <p style={{ color:'#6b8080', fontSize:16, marginBottom:24 }}>
        Xorazm viloyati bo'ylab universal yetkazib berish
      </p>
      <a href="/orders/new" style={{ display:'inline-block', padding:'13px 32px',
        background:'#0D7A6A', color:'#fff', borderRadius:10, fontWeight:700,
        fontSize:16, textDecoration:'none' }}>
        Buyurtma berish →
      </a>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <AuthProvider>
        <Toaster position="top-right" toastOptions={{ duration: 3000 }} />
        <Navbar />
        <main style={{ minHeight:'calc(100vh - 58px)', background:'#F7F9F8' }}>
          <Routes>
            {/* Public */}
            <Route path="/login" element={<LoginPage />} />

            {/* Customer */}
            <Route path="/" element={<HomePage />} />
            <Route path="/orders/new" element={
              <PrivateRoute roles={['CUSTOMER','FARMER']}>
                <CreateOrderPage />
              </PrivateRoute>
            } />
            <Route path="/orders" element={
              <PrivateRoute><MyOrdersPage /></PrivateRoute>
            } />
            <Route path="/orders/:id" element={
              <PrivateRoute><TrackingPage /></PrivateRoute>
            } />

            {/* Courier */}
            <Route path="/courier" element={
              <PrivateRoute roles={['COURIER']}>
                <CourierDashboard />
              </PrivateRoute>
            } />

            {/* Admin */}
            <Route path="/admin" element={
              <PrivateRoute roles={['ADMIN']}>
                <AdminDashboard />
              </PrivateRoute>
            } />

            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </AuthProvider>
    </BrowserRouter>
  );
}
